using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    [ColumnName("Score")]
    public float[] Score { get; set; } = [];
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService(ILogger<ModelTrainerService> logger)
{
    public void TrainAndSaveModel(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketInput.Category),
                keyOrdinality: Microsoft.ML.Transforms.ValueToKeyMappingEstimator.KeyOrdinality.ByValue)
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        logger.LogInformation("========== Model Evaluation Metrics ==========");
        logger.LogInformation("Macro Accuracy:     {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("Micro Accuracy:     {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("Log Loss:           {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);
        logger.LogInformation("Confusion Matrix:\n{ConfusionMatrix}",
            metrics.ConfusionMatrix.GetFormattedConfusionTable());
        logger.LogInformation("===============================================");

        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionPool) : ControllerBase
{
    // Alphabetical order matches KeyOrdinality.ByValue used during training
    private static readonly string[] Labels = ["Billing", "General", "Technical"];

    [HttpPost("classify")]
    public ActionResult<TicketClassifyResponse> Classify([FromBody] TicketClassifyRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionPool.Predict(input);

        var scores = Labels
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => pair.Second);

        return Ok(new TicketClassifyResponse(
            prediction.Category,
            prediction.Score.Max(),
            scores));
    }
}

public record TicketClassifyRequest(string Subject, string Description, int Priority);

public record TicketClassifyResponse(
    string Category,
    float Confidence,
    Dictionary<string, float> Scores);

