using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainerService>();

var modelPath = Path.Combine(AppContext.BaseDirectory, "MLModel.zip");
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

// Train and evaluate model before accepting requests
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
app.Services.GetRequiredService<ModelTrainerService>()
    .TrainAndSaveModel(dataPath, modelPath);

app.MapControllers();
app.Run();

